if (! function_exists('file_lock')) {
    function file_lock($operation, $name = null, $timeout = null, $data = null)
    {
        // Cross-process file locking using PHP's flock()
        // Supports exclusive (write) and shared (read) locks on named lock files

        $operation = isset($operation) ? (string)$operation : '';
        $lock_name = isset($name) ? (string)$name : 'default';
        $timeout = isset($timeout) ? min(max((int)$timeout, 5), 120) : 10;
        $lock_data = isset($data) ? (string)$data : '';

        if ($operation === '') {
            return ['error' => 'Operation required: acquire_exclusive, acquire_shared, release, try_exclusive, try_shared'];
        }

        // Lock files are stored in workspace/locks/ directory
        $lock_dir = __DIR__ . '/../../workspace/locks';
        if (!is_dir($lock_dir)) {
            @mkdir($lock_dir, 0755, true);
        }

        // Sanitize lock name for filesystem
        $safe_name = preg_replace('/[^a-zA-Z0-9._-]/', '_', $lock_name);
        $lock_path = $lock_dir . '/' . $safe_name . '.lock';

        // Use a persistent store to track which locks this process holds
        // Since each tool call runs in a fresh process, track locally
        $lock_handle = null;

        try {
            switch ($operation) {
                case 'acquire_exclusive':
                case 'acquire_shared':
                    $is_exclusive = ($operation === 'acquire_exclusive');
                    $lock_flag = $is_exclusive ? LOCK_EX : LOCK_SH;
                    
                    $start = microtime(true);
                    $handle = @fopen($lock_path, 'c+');
                    if (!$handle) {
                        return ['error' => "Failed to open/create lock file: {$lock_path}"];
                    }
                    
                    // Write initial data if the file is new/empty
                    @flock($handle, LOCK_EX); // briefly lock to write metadata
                    if (filesize($lock_path) === 0 && $lock_data !== '') {
                        @fwrite($handle, $lock_data);
                        @fflush($handle);
                    }
                    @flock($handle, LOCK_UN); // unlock before acquiring our real lock
                    
                    // Acquire the lock (blocking)
                    $acquired = @flock($handle, $lock_flag);
                    $waited = round((microtime(true) - $start) * 1000, 1);
                    
                    if (!$acquired) {
                        fclose($handle);
                        return ['error' => 'Failed to acquire lock (unexpected)'];
                    }
                    
                    // Re-read lock file content
                    @rewind($handle);
                    $content = @stream_get_contents($handle);
                    if ($content === false) $content = '';
                    
                    // Store handle globally for later release
                    $GLOBALS['_lock_handles'][$safe_name] = $handle;
                    
                    return [
                        'success' => true,
                        'operation' => $operation,
                        'lock' => $safe_name,
                        'path' => $lock_path,
                        'acquired' => true,
                        'wait_ms' => $waited,
                        'content' => rtrim($content),
                        'type' => $is_exclusive ? 'exclusive' : 'shared',
                        'note' => 'Lock held. Call release to unlock, or the lock auto-releases when this process exits.',
                    ];
                    
                case 'try_exclusive':
                case 'try_shared':
                    $is_exclusive = ($operation === 'try_exclusive');
                    $is_shared = ($operation === 'try_shared');
                    $lock_flag = $is_exclusive ? (LOCK_EX | LOCK_NB) : (LOCK_SH | LOCK_NB);
                    
                    $handle = @fopen($lock_path, 'c+');
                    if (!$handle) {
                        return ['error' => "Failed to open lock file: {$lock_path}"];
                    }
                    
                    $acquired = @flock($handle, $lock_flag);
                    
                    if (!$acquired) {
                        fclose($handle);
                        return [
                            'success' => true,
                            'operation' => $operation,
                            'lock' => $safe_name,
                            'acquired' => false,
                            'message' => 'Lock is held by another process',
                            'type' => $is_exclusive ? 'exclusive' : 'shared',
                        ];
                    }
                    
                    $GLOBALS['_lock_handles'][$safe_name] = $handle;
                    
                    return [
                        'success' => true,
                        'operation' => $operation,
                        'lock' => $safe_name,
                        'acquired' => true,
                        'type' => $is_exclusive ? 'exclusive' : 'shared',
                        'note' => 'Lock acquired (non-blocking). Call release to unlock.',
                    ];
                    
                case 'release':
                    $released = false;
                    if (isset($GLOBALS['_lock_handles'][$safe_name])) {
                        $handle = $GLOBALS['_lock_handles'][$safe_name];
                        $released = @flock($handle, LOCK_UN);
                        @fclose($handle);
                        unset($GLOBALS['_lock_handles'][$safe_name]);
                    } else {
                        // Lock wasn't acquired in this process, try to release anyway
                        $handle = @fopen($lock_path, 'c+');
                        if ($handle) {
                            $released = @flock($handle, LOCK_UN);
                            @fclose($handle);
                        }
                    }
                    
                    return [
                        'success' => true,
                        'operation' => 'release',
                        'lock' => $safe_name,
                        'released' => true,
                    ];
                    
                default:
                    return ['error' => "Unknown operation: {$operation}"];
            }
            
        } catch (\Throwable $e) {
            if (isset($handle) && $handle) @fclose($handle);
            return ['error' => 'File locking failed: ' . $e->getMessage()];
        }
    }
